const { mkdirSync, readdirSync } = require('fs');
const path = require('path');
const cfg = $('Konfiguration').first().json;
const ausgeschlossen = new Set(cfg.ausgeschlosseneOrdner || []);

// Spiegelt die Ordnerstruktur von Input/ nach WHITESTAG-Vault/
// Ordner die mit _ beginnen (z.B. _fehler) oder in der Ausschlussliste stehen werden uebersprungen
function syncDirs(src, dst) {
  let entries;
  try { entries = readdirSync(src, { withFileTypes: true }); } catch(e) { return; }
  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    if (entry.name.startsWith('_')) continue;
    if (ausgeschlossen.has(entry.name)) continue;
    mkdirSync(path.join(dst, entry.name), { recursive: true });
    syncDirs(path.join(src, entry.name), path.join(dst, entry.name));
  }
}

try {
  syncDirs(cfg.pfade.quelle, cfg.pfade.ziel);
} catch(e) {}

return $input.all();

const { execSync } = require('child_process');
const path = require('path');
const cfg = $('Konfiguration').first().json;
const startTime = Date.now();

// Ausschlussmuster bauen
const ausgeschlossen = (cfg.ausgeschlosseneOrdner || []).map(o => `-not -path '*/${o}/*'`).join(' ');
const findBase = `find "${cfg.pfade.quelle}" -type f \\( -name '*.docx' -o -name '*.pdf' -o -name '*.txt' -o -name '*.rtf' -o -name '*.md' \\) -not -path '*/_fehler/*' ${ausgeschlossen}`;

// Erste Datei holen
let filePath = '';
try {
  filePath = execSync(`${findBase} -print -quit 2>/dev/null`, { encoding: 'utf8', stdio: 'pipe' }).trim();
} catch(e) { return []; }

if (!filePath) return [];

// Gesamtzahl verbleibender Dateien zählen (inkl. aktuelle)
// maxBuffer auf 10MB erhöhen – bei vielen Dateien sonst Buffer-Overflow → leere Ausgabe
let verbleibend = 0;
try {
  const liste = execSync(`${findBase} 2>/dev/null`, { encoding: 'utf8', stdio: 'pipe', maxBuffer: 10 * 1024 * 1024 }).trim();
  verbleibend = liste ? liste.split('\n').length : 0;
} catch(e) { verbleibend = 0; }

const fileName   = filePath.split('/').pop();
const lastDot    = fileName.lastIndexOf('.');
const baseName   = lastDot > 0 ? fileName.slice(0, lastDot) : fileName;
const ext        = lastDot > 0 ? fileName.slice(lastDot + 1).toLowerCase() : '';
const uid        = Date.now() + '_' + Math.random().toString(36).slice(2);
const mdTempPath = '/tmp/c2md_' + uid + '.md';
const anlagenDir = path.dirname(filePath) + '/' + baseName;

const relDir = path.dirname(filePath).slice(cfg.pfade.quelle.length + 1);
const typ = relDir || 'Unsortiert';

let command;
if      (ext === 'pdf')  command = `"${cfg.tools.pdftotext}" -layout "${filePath}" "${mdTempPath}"`;
else if (ext === 'docx') command = `"${cfg.tools.pandoc}" -f docx -t markdown --wrap=none "${filePath}" -o "${mdTempPath}"`;
else if (ext === 'rtf')  command = `"${cfg.tools.pandoc}" -f rtf -t markdown --wrap=none "${filePath}" -o "${mdTempPath}"`;
else if (ext === 'txt')  command = `"${cfg.tools.iconv}" -f UTF-8 -t UTF-8 "${filePath}" 2>/dev/null | sed 's/^\\xef\\xbb\\xbf//' > "${mdTempPath}"`;
else                     command = `cp "${filePath}" "${mdTempPath}"`;

return [{ json: { filePath, fileName, baseName, ext, mdTempPath, command, anlagenDir, typ, verbleibend, startTime } }];

const { execSync } = require('child_process');
const { mkdirSync, renameSync, existsSync } = require('fs');
const cfg = $('Konfiguration').first().json;
const results = [];

for (const item of $input.all()) {
  const { filePath, fileName, baseName, ext, mdTempPath, command, anlagenDir, typ } = item.json;
  try {
    // Konvertierung ausfuehren (pandoc / pdftotext / iconv / cp)
    execSync(command, { encoding: 'utf8', shell: '/bin/bash', stdio: 'pipe' });
    results.push({ json: { filePath, fileName, baseName, ext, mdTempPath, anlagenDir, typ } });
  } catch(e) {
    // Bei Fehler: Originaldatei in _fehler verschieben – fs.renameSync vermeidet Shell-Sonderzeichen-Probleme
    try {
      mkdirSync(cfg.pfade.fehler, { recursive: true });
      renameSync(filePath, cfg.pfade.fehler + '/' + fileName);
    } catch(e2) {}
  }
}

return results;

const { execSync } = require('child_process');
const cfg   = $('Konfiguration').first().json;
const today = new Date().toISOString().slice(0, 10);

// System-Prompt wird einmal gebaut und fuer alle Items wiederverwendet
const systemPrompt =
  'Du analysierst Dokumente fuer eine Obsidian-Wissensdatenbank. Gib ausschliesslich valides JSON zurueck - kein Markdown, keine Erklaerung.\n\n' +
  'VAULT-INHABER (wichtig fuer Rechnungs-Routing):\n' +
  '  Name: ' + cfg.inhaber.name + '\n' +
  '  Unternehmen: ' + cfg.inhaber.unternehmen + '\n\n' +
  // Rechnungsausgang = WHITESTAG ist Absender, Rechnungseingang = WHITESTAG ist Empfaenger
  'RECHNUNGS-ROUTING (PFLICHT – Briefkopf und Empfaenger genau pruefen):\n' +
  '  Rechnungsausgang (ABSENDER = ' + cfg.inhaber.unternehmen + ' / ' + cfg.inhaber.name + '):\n' +
  '    rechnungsadressat: "' + cfg.inhaber.unternehmen + '"\n' +
  '    rechnungsempfaenger: Kundenname aus dem Dokument\n' +
  '    kunde: "" (immer leer bei Rechnungen)\n' +
  '  Rechnungseingang (EMPFAENGER = ' + cfg.inhaber.unternehmen + ' / ' + cfg.inhaber.name + '):\n' +
  '    rechnungsadressat: Absenderfirma aus dem Dokument\n' +
  '    rechnungsempfaenger: "' + cfg.inhaber.unternehmen + '"\n' +
  '    kunde: "" (immer leer bei Rechnungen)\n\n' +
  // E-Mail-spezifische Felder – nur befuellen wenn subtyp = E-Mail
  'E-MAIL-FELDER (nur befuellen wenn subtyp = E-Mail):\n' +
  '  von: Vollstaendige Absenderadresse inkl. Name\n' +
  '  an: Vollstaendige Empfaengeradresse inkl. Name\n' +
  '  anhaenge: Array der Dateinamen aller Attachments; sonst []\n' +
  '  kunde: Die Gegenseite (nicht-WHITESTAG-Partei) aus Von/An\n' +
  '  teilnehmer: immer [] bei E-Mails\n\n' +
  'Felder:\n' +
  '- title: Praegnanter, konkreter Titel (NICHT generisch) – bei E-Mails: Subject-Zeile\n' +
  '- datum: Datum IM Dokument als YYYY-MM-DD; falls nicht erkennbar: heutiges Datum\n' +
  '- subtyp: Konkreter Untertyp basierend auf Inhalt. Eines von: ' + cfg.metatags.subtypen.join(' | ') + '\n' +
  '- status: Eines von: ' + cfg.metatags.status.join(' | ') + '\n' +
  '- tags: Array mit 2-5 Schlagwoertern aus: ' + cfg.metatags.tagVokabular.join(', ') + '\n' +
  '- kunde: Firmen- oder Kundenname – bei Rechnungen immer leer lassen\n' +
  '- projekt: Konkreter Projektname, sonst leerer String\n' +
  '- rechnungsnummer: Rechnungsnummer aus dem Dokument, sonst leerer String\n' +
  '- rechnungsadressat: Nur bei Rechnungen: Rechnungssteller/Absender; sonst leerer String\n' +
  '- rechnungsempfaenger: Nur bei Rechnungen: Rechnungsempfaenger; sonst leerer String\n' +
  '- von: Nur bei E-Mails: Absender; sonst leerer String\n' +
  '- an: Nur bei E-Mails: Empfaenger; sonst leerer String\n' +
  '- anhaenge: Nur bei E-Mails: Array der Anhang-Dateinamen; sonst []\n' +
  '- teilnehmer: Array aller genannten Personen (nur bei Meetings), sonst []\n' +
  '- zusammenfassung: 2 konkrete Saetze – WAS wird besprochen oder entschieden';

const results = [];

for (const item of $input.all()) {
  const { filePath, fileName, baseName, ext, mdTempPath, anlagenDir, typ, verbleibend, startTime } = item.json;

  // Nur ersten 4000 Bytes lesen – reicht fuer Metadaten-Erkennung und spart LLM-Tokens
  const mdContent = execSync(
    `head -c 4000 "${mdTempPath}" 2>/dev/null || echo ""`,
    { encoding: 'utf8', stdio: 'pipe' }
  );

  const userPrompt =
    'Dateiname: ' + fileName + '\n' +
    'Dokumenttyp (aus Eingangsordner): ' + typ + '\n' +
    'Heutiges Datum: ' + today + '\n\n' +
    'Dokumentinhalt (Auszug):\n' + mdContent.slice(0, 2500);

  results.push({ json: { filePath, fileName, baseName, ext, mdTempPath, anlagenDir, typ, verbleibend, startTime, systemPrompt, userPrompt } });
}

return results;

const { execSync } = require('child_process');
const { writeFileSync, readFileSync, existsSync, statSync, mkdirSync, renameSync, copyFileSync, unlinkSync, readdirSync } = require('fs');
const path = require('path');
const cfg      = $('Konfiguration').first().json;
const fileData = $('Inhalt lesen und Anfrage vorbereiten').item.json;
const today    = new Date().toISOString().slice(0, 10);
const esc      = s => (s || '').toString().replace(/"/g, "'"); // Anführungszeichen in YAML escapen

// ── LLM-Antwort parsen ───────────────────────────────────────
// Markdown-Codeblöcke entfernen falls LLM diese trotz Anweisung liefert
let meta = {};
try {
  const raw     = ($input.item.json.output || '').trim();
  const jsonStr = raw.replace(/^```json?\s*/i, '').replace(/\s*```$/i, '').trim();
  meta = JSON.parse(jsonStr);
} catch(e) {
  meta = {}; // Fallback: leere Metadaten, Defaults greifen unten
}

// ── Zielordner bestimmen ─────────────────────────────────────
// Ordnerstruktur aus Input/ wird 1:1 in WHITESTAG-Vault/ gespiegelt
const targetDir       = cfg.pfade.ziel + '/' + fileData.typ;
const attachmentsDir  = targetDir + '/attachments';
const mdFinalPath     = targetDir + '/' + fileData.baseName + '.md';
const attachFinalPath = attachmentsDir + '/' + fileData.fileName;

// E-Mail-Erkennung via subtyp (vom LLM)
const istEmailSubtyp  = (meta.subtyp || '').toLowerCase() === 'e-mail';

// ── YAML Frontmatter aufbauen ────────────────────────────────
const tagsYaml = Array.isArray(meta.tags) && meta.tags.length
  ? meta.tags.map(t => '  - ' + t).join('\n')
  : '  - Unsortiert';

// teilnehmer nur bei Meetings sinnvoll, nicht bei E-Mails
const teilnehmerYaml = !istEmailSubtyp && Array.isArray(meta.teilnehmer) && meta.teilnehmer.length
  ? '\nteilnehmer:\n' + meta.teilnehmer.map(t => '  - "' + esc(t) + '"').join('\n')
  : '';

// anhaenge nur bei E-Mails befuellen
const anhaengeYaml = istEmailSubtyp && Array.isArray(meta.anhaenge) && meta.anhaenge.length
  ? 'anhaenge:\n' + meta.anhaenge.map(a => '  - "' + esc(a) + '"').join('\n') + '\n'
  : '';

const frontmatter =
  '---\n' +
  'title: "'                + esc(meta.title || fileData.baseName) + '"\n' +
  'datum: '                 + (meta.datum  || today) + '\n' +
  'erstellt: '              + today + '\n' +
  'typ: '                   + fileData.typ + '\n' +
  'subtyp: '                + (meta.subtyp || '') + '\n' +
  'status: '                + (meta.status || 'Archiviert') + '\n' +
  'tags:\n'                 + tagsYaml + '\n' +
  'kunde: "'                + esc(meta.kunde)   + '"\n' +
  'projekt: "'              + esc(meta.projekt) + '"\n' +
  // Rechnungsfelder – nur wenn vorhanden
  (meta.rechnungsnummer     ? 'rechnungsnummer: "'     + esc(meta.rechnungsnummer)     + '"\n' : '') +
  (meta.rechnungsadressat   ? 'rechnungsadressat: "'   + esc(meta.rechnungsadressat)   + '"\n' : '') +
  (meta.rechnungsempfaenger ? 'rechnungsempfaenger: "' + esc(meta.rechnungsempfaenger) + '"\n' : '') +
  // E-Mail-Felder – nur wenn vorhanden
  (meta.von                 ? 'von: "'                 + esc(meta.von)                 + '"\n' : '') +
  (meta.an                  ? 'an: "'                  + esc(meta.an)                  + '"\n' : '') +
  anhaengeYaml +
  teilnehmerYaml + '\n' +
  'zusammenfassung: "'      + esc(meta.zusammenfassung) + '"\n' +
  'quelle: "'               + fileData.fileName + '"\n' +
  '---\n\n';

// ── Frontmatter + Originalinhalt in Temp-Datei schreiben ─────
const originalContent = readFileSync(fileData.mdTempPath, 'utf8');
writeFileSync(fileData.mdTempPath, frontmatter + originalContent, 'utf8');

// ── Zielverzeichnisse erstellen ──────────────────────────────
// mkdirSync statt Shell-mkdir – kein Problem mit Sonderzeichen
mkdirSync(targetDir,      { recursive: true });
mkdirSync(attachmentsDir, { recursive: true });

// ── MD-Datei verschieben ─────────────────────────────────────
// /tmp → SMB-Share = geraeteuebergreifend: copyFileSync + unlinkSync statt renameSync
// renameSync wuerde EXDEV (cross-device link not permitted) werfen
copyFileSync(fileData.mdTempPath, mdFinalPath);
unlinkSync(fileData.mdTempPath);

// ── Originaldatei verschieben oder löschen (Race-Condition-Schutz) ───
// .md-Originale werden gelöscht (Inhalt ist bereits im Vault mit Frontmatter)
// Alle anderen Formate (.docx, .pdf, .txt, .rtf) → nach attachments/ verschieben
if (existsSync(fileData.filePath)) {
  if (fileData.ext === 'md') {
    unlinkSync(fileData.filePath);
  } else {
    mkdirSync(attachmentsDir, { recursive: true });
    renameSync(fileData.filePath, attachFinalPath);
  }
}

// ── Anlagen-Ordner mitverschieben (E-Mail-Attachments) ───────
// Erwartet: Ordner mit gleichem Namen wie die .txt-Datei (ohne Extension)
if (fileData.anlagenDir && existsSync(fileData.anlagenDir) && statSync(fileData.anlagenDir).isDirectory()) {
  // Alle Dateien im Anlagen-Ordner einzeln verschieben – renameSync ist sicher bei Sonderzeichen
  for (const f of readdirSync(fileData.anlagenDir)) {
    const src = path.join(fileData.anlagenDir, f);
    const dst = path.join(attachmentsDir, f);
    if (statSync(src).isFile()) {
      renameSync(src, dst); // ueberschreibt gleichnamige Dateien
    }
  }
  // Leeren Ordner entfernen
  try { execSync(`rmdir "${fileData.anlagenDir}"`, { stdio: 'pipe' }); } catch(e) {}
}

// ── resources/-Ordner kopieren (Onenote-Bilder) ──────────────
const sourceResourcesDir = path.dirname(fileData.filePath) + '/resources';
const targetResourcesDir = targetDir + '/resources';
if (existsSync(sourceResourcesDir) && statSync(sourceResourcesDir).isDirectory()) {
  mkdirSync(targetResourcesDir, { recursive: true });
  for (const f of readdirSync(sourceResourcesDir)) {
    const src = path.join(sourceResourcesDir, f);
    const dst = path.join(targetResourcesDir, f);
    if (statSync(src).isFile() && !existsSync(dst)) {
      copyFileSync(src, dst);
    }
  }
}

// ── Status-Datei aktualisieren ───────────────────────────────
const statusPath  = cfg.pfade.ziel + '/_status.md';
// Dauer: Zeit zwischen startTime (Datei suchen) und jetzt
const dauerSek    = fileData.startTime ? Math.max(1, Math.round((Date.now() - fileData.startTime) / 1000)) : 1;
// Verbleibend: gezählte Dateien minus aktuelle (die gerade fertig wird)
const verbleibend = Math.max(0, (fileData.verbleibend || 1) - 1);

// Rollender Durchschnitt: letzte Messungen aus Status-Datei lesen
let messungen = [];
try {
  const prev = readFileSync(statusPath, 'utf8');
  const match = prev.match(/<!--messungen:(.*?)-->/);
  if (match) messungen = JSON.parse(match[1]);
} catch(e) {}
messungen.push(dauerSek);
if (messungen.length > 20) messungen = messungen.slice(-20);
const avgSek = Math.round(messungen.reduce((a, b) => a + b, 0) / messungen.length);
const restSek = verbleibend * avgSek;
const restMin = Math.round(restSek / 60);
const now = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

const statusContent =
  '# Import-Status\n\n' +
  `**Verbleibend:** ${verbleibend} Dateien\n` +
  `**Ø Dauer:** ${avgSek} Sek./Datei\n` +
  `**Geschätzte Restzeit:** ~${restMin} Minuten\n` +
  `**Zuletzt verarbeitet:** ${fileData.fileName} (${now})\n\n` +
  `<!--messungen:${JSON.stringify(messungen)}-->`;
try { writeFileSync(statusPath, statusContent, 'utf8'); } catch(e) {}

return { json: { ok: true, datei: fileData.fileName, zielordner: fileData.typ, subtyp: meta.subtyp || '', kunde: meta.kunde || '', verbleibend, dauerSek } };
